return [{ json: { url: 'https://kipuhealth.zendesk.com/api/v2/users.json?role[]=agent&page=1&per_page=100' } }];

const data = $getWorkflowStaticData('global');
const body = $('Fetch Users Page').first().json;
const rowCount = $('Pack User Rows JSON').first().json.row_count || 0;
data.users_pages_loaded = (data.users_pages_loaded || 0) + 1;
data.users_rows_loaded = (data.users_rows_loaded || 0) + rowCount;
return [{ json: { next_page: body.next_page || null, page_row_count: rowCount, pages_loaded: data.users_pages_loaded, total_rows_loaded: data.users_rows_loaded, end_of_stream: !body.next_page } }];

const data = $getWorkflowStaticData('global');
data.ticket_ids = [];
data.export_count = 0;

const body = $json.body || $json;
const date_from = body.date_from;
const date_to = body.date_to;
const form_id = body.form_id;
const form_name = body.form_name;

if (!form_id || !date_from || !date_to) {
  throw new Error('form_id, form_name, date_from, and date_to are required');
}

data.form_name = form_name;

const queryParts = [
  'type:ticket',
  `ticket_form_id:${form_id}`,
  `created>=${date_from}`,
  `created<${date_to}`
];

queryParts.push('custom_field_1260824167549:support_');


const query = queryParts.join(' ');
const url = `https://kipuhealth.zendesk.com/api/v2/search/export.json?query=${encodeURIComponent(query)}&filter[type]=ticket`;

return [{ json: { url, date_from, date_to, form_id, form_name } }];

const results = $json.results || [];
const data = $getWorkflowStaticData('global');

if (!data.ticket_ids) data.ticket_ids = [];
data.ticket_ids = data.ticket_ids.concat(results.map(t => t.id));

return [{
  json: {
    url: $json.links?.next || null,
    total_count: data.ticket_ids.length,
    has_more: $json.meta?.has_more,
    pages_so_far: Math.ceil(data.ticket_ids.length / 100)
  }
}];

const data = $getWorkflowStaticData('global');
const ids = data.ticket_ids || [];

data.ticket_ids = [];
data.export_count = 0;

const batches = [];
for (let i = 0; i < ids.length; i += 100) {
  batches.push(ids.slice(i, i + 100));
}

return batches.map(batch => ({
  json: {
    ids: batch.join(','),
    count: batch.length
  }
}));

const ARTICLE_LINKED_FIELD_IDS = [18158428639387, 25171038337691];

function getCustomFieldValue(ticket, fieldIds) {
  const fields = Array.isArray(ticket.custom_fields) ? ticket.custom_fields : [];
  for (const fieldId of fieldIds) {
    const match = fields.find(f => Number(f.id) === Number(fieldId));
    if (match && match.value != null && match.value !== '') return match.value;
  }
  return null;
}

function hasAnyTag(ticket, tagList) {
  const tags = Array.isArray(ticket.tags) ? ticket.tags : [];
  return tagList.some(tag => tags.includes(tag));
}

function getArticleLinkedFlag(ticket) {
  const raw = getCustomFieldValue(ticket, ARTICLE_LINKED_FIELD_IDS);
  if (raw === 'kcs_linked_yes' || raw === 'kcslinked_yes') return true;
  if (raw === 'kcs_linked_no' || raw === 'kcslinked_no') return false;
  if (hasAnyTag(ticket, ['kcs_linked_yes', 'kcslinked_yes'])) return true;
  if (hasAnyTag(ticket, ['kcs_linked_no', 'kcslinked_no'])) return false;
  return null;
}

function getSlaBreachedFlag(ticket, metric) {
  const policyMetrics = Array.isArray(ticket.slas?.policy_metrics)
    ? ticket.slas.policy_metrics : [];
  if (!policyMetrics.length) return null;
  const solvedAt = metric?.solved_at ? new Date(metric.solved_at) : null;
  return policyMetrics.some(m => {
    if (!m.breach_at) return false;
    if (solvedAt) return new Date(m.breach_at) < solvedAt;
    return m.stage === 'breached';
  });
}

const allTickets = [];
for (const item of $input.all()) {
  const tickets = item.json.tickets || [];
  allTickets.push(...tickets);
}

return allTickets.map(t => {
  const m = t.metric_set || {};
  const resolution = m.full_resolution_time_in_minutes?.business ?? null;

  return {
    json: {
      ticket_id: t.id,
      ticket_created_at: t.created_at,
      ticket_updated_at: t.updated_at,
      ticket_solved_at: m.solved_at ?? t.solved_at ?? null,
      status: t.status,
      channel: t.via?.channel || null,
      form_id: t.ticket_form_id || null,
      form_name: null,
      assignee_id: t.assignee_id || null,
      group_id: t.group_id || null,
      csat_score: t.satisfaction_rating?.score || null,
      first_reply_time_business_minutes: m.reply_time_in_minutes?.business ?? null,
      next_reply_time_business_minutes: null,
      pausable_update_time_business_minutes: m.on_hold_time_in_minutes?.business ?? null,
      requester_wait_time_business_minutes: m.requester_wait_time_in_minutes?.business ?? null,
      full_resolution_time_business_minutes: resolution,
      one_business_day_solve_flag: resolution != null ? resolution <= 480 : null,
      sla_breached_flag: getSlaBreachedFlag(t, m),
      article_linked_flag: getArticleLinkedFlag(t),
      missed_call_flag: null,
      ticket_count: 1,
      synced_at: new Date().toISOString()
    }
  };
});

const fields = $json.ticket_fields || [];
return [{
  json: {
    fields: fields.map(f => ({
      id: f.id,
      title: f.title,
      type: f.type,
      key: f.key
    }))
  }
}];

const body = $json.body || $json;
const form_id = body.form_id;
const form_name = body.form_name;
const date_from = body.date_from;
const date_to = body.date_to;

const query = `type:ticket ticket_form_id:${form_id} created>=${date_from} created<${date_to} custom_field_1260824167549:support_`;

return [{ json: { 
  url: `https://kipuhealth.zendesk.com/api/v2/search/count.json?query=${encodeURIComponent(query)}`,
  form_id,
  form_name,
  date_from,
  date_to,
  zendesk_query: query
} }];

