const res = $json;
return [{ json: { 
  source: 'zendesk', 
  filters: { 
    form_id: req.form_id, 
    form_name: req.form_name, 
    date_from: req.date_from, 
    date_to: req.date_to, 
    query_used: req.zendesk_query 
  }, 
  total_found: res.count ?? 0 
} }];
